        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "AI Assistant Overview",
            Slug = "ai-overview",
            Summary = "What the AI Assistant feature does, how conversations work, and how to get the most out of domain-specific assistants.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/ai"]""",
            Tags = """["ai","assistant","chat"]""",
            ContentJson = """{"body":"## AI Assistant Overview\n\nThe AI Assistant gives you a set of AI helpers that can answer questions, draft content, and help with everyday tasks. Each one is focused on a specific area — HR, Purchasing, Sales, or general work — so the answers fit what you're doing.\n\n### How It Works\n\nThe AI page has two sides:\n- **Sidebar (left):** A list of assistants. Each card shows its name and a short description, and the one you're using is highlighted.\n- **Chat area (right):** Where the conversation happens. When you first pick an assistant, you'll see a welcome screen with its name, description, and a few starter questions to get you going.\n\n### Starting a Conversation\n\nClick an assistant in the sidebar to select it. If you haven't chatted with it yet, you'll see the welcome screen with starter questions. Click a starter question, or type your own in the box at the bottom.\n\n### The Message Box\n\n- Type your question in the box. The hint text names the assistant you're talking to.\n- Press **Enter** to send, or **Shift+Enter** to add a new line.\n- **Send** is greyed out when the box is empty or a reply is still coming.\n- **Clear Chat** clears the conversation and returns to the welcome screen. It only shows once you've sent at least one message.\n\n### How Context Works\n\nThe assistant reads your recent messages so it can follow up on what you asked before. Each assistant keeps its own conversation while you stay on the page — switch away and back and your chat is still there for this session. Conversations aren't saved between sessions, so closing the browser clears them.\n\n### Assistant Replies\n\nReplies appear on the left. While the assistant is thinking, you'll see three moving dots. Answers can include headings, lists, and code, depending on the question.\n\n### When to Use the AI Assistant\n\n- When you need a quick answer about a process or policy\n- When drafting job descriptions, emails, or documentation\n- When you want to find answers across your uploaded documents\n- When exploring what-if ideas for purchasing or sales\n- When you need help making sense of quality or production data","sections":[]}"""
        });

