            ContentJson = """{"title":"AI Assistant Field Reference","groups":[{"heading":"Sidebar Elements","items":[{"label":"Assistant Card","value":"Shows each assistant's icon, name, and description. Click to select. The one you're using is highlighted."},{"label":"Icon","value":"A small picture that hints at the assistant's area — for example a graduation cap for HR, a cart for purchasing. Set by your admin."},{"label":"Name","value":"The assistant's name, such as 'HR Assistant' or 'Sales Advisor'. Set by your admin."},{"label":"Description","value":"A short summary of what the assistant is good at. Shown on the card and welcome screen."},{"label":"Active Indicator","value":"A highlight on the assistant you're currently using. Only one is active at a time."}]},{"heading":"Chat Area — Welcome Screen","items":[{"label":"Assistant Icon (large)","value":"The selected assistant's icon, shown large and centered above its name."},{"label":"Assistant Name","value":"A large heading showing which assistant you're chatting with."},{"label":"Assistant Description","value":"A fuller description of what the assistant can help with."},{"label":"Starter Questions","value":"A set of clickable questions. Each assistant has its own, set by your admin. Click one to send it as your first message."}]},{"heading":"Chat Area — Message Thread","items":[{"label":"Your Messages","value":"Bubbles on the right showing what you sent, marked with your initials."},{"label":"Assistant Messages","value":"Bubbles on the left showing the assistant's replies. Can include headings, lists, and code."},{"label":"Typing Indicator","value":"Three moving dots that appear while the assistant is writing its reply."},{"label":"Message History","value":"The scrollable list of messages in this conversation. The assistant looks back at your last few messages so it can follow the thread."}]},{"heading":"Buttons and Actions","items":[{"label":"Send","value":"Sends your message to the assistant. Greyed out when the box is empty or while a reply is coming. You can also just press Enter."},{"label":"Clear Chat","value":"Clears the current assistant's conversation and returns to the welcome screen. It only shows in the chat header once you've sent at least one message — before that it's hidden. It doesn't touch your other assistants' chats."},{"label":"Starter Question","value":"Click one to send it as your first message and start the conversation."},{"label":"Assistant Card","value":"Click to switch assistants. Each assistant keeps its own conversation for the rest of your session."}]},{"heading":"Input Behavior","items":[{"label":"Message Box","value":"A text box that holds multiple lines. The hint text names the assistant you're talking to."},{"label":"Enter","value":"Sends the message — the same as clicking Send."},{"label":"Shift+Enter","value":"Adds a new line without sending. Use it for longer, multi-line questions."},{"label":"Empty Box","value":"Send is greyed out. You can't send an empty message."},{"label":"While Sending","value":"Send is greyed out and shows a busy state until the assistant replies."}]},{"heading":"Good to Know","items":[{"label":"Which Assistants You See","value":"The sidebar lists the assistants your admin has set up and turned on. New or changed assistants show up right away."},{"label":"How Replies Work","value":"When you send a question, the assistant reads your recent messages for context and writes a reply. You get the answer in the chat."},{"label":"Conversations Aren't Saved","value":"Each assistant keeps its own chat only for your current session. Closing or refreshing the browser clears them all."},{"label":"Sharing a Link","value":"The assistant you're on is part of the page address, so you can copy the link and share it. A coworker who opens it lands on that assistant's welcome screen."}]}]}"""
