            AppRoutes = """["/ai"]""",
            Tags = """["ai","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ai1","text":"You want to ask the HR Assistant about the company's PTO policy. How do you start?","options":[{"id":"a","text":"Go to Admin → AI Settings and type your question in the configuration panel"},{"id":"b","text":"Navigate to the AI page, click the HR Assistant card in the sidebar, then type your question or click a starter question","isCorrect":true},{"id":"c","text":"Open the Chat feature and create a new room called 'HR Questions'"},{"id":"d","text":"Go to Training → search for PTO policy in the module list"}],"explanation":"Navigate to the AI page (/ai), select the HR Assistant from the sidebar, and either type your question in the input or click one of the starter questions on the welcome screen."},{"id":"ai2","text":"You're chatting with the Sales Advisor and want to start a new line in your message without sending it. What key combination do you use?","options":[{"id":"a","text":"Ctrl+Enter"},{"id":"b","text":"Alt+Enter"},{"id":"c","text":"Shift+Enter","isCorrect":true},{"id":"d","text":"Tab then Enter"}],"explanation":"Shift+Enter inserts a new line in the message input. Pressing Enter alone sends the message."},{"id":"ai3","text":"How many of your previous messages does the AI assistant use as context when generating a response?","options":[{"id":"a","text":"All messages from the entire conversation"},{"id":"b","text":"The last 10 messages","isCorrect":true},{"id":"c","text":"Only your most recent message — no history"},{"id":"d","text":"The last 50 messages or 4000 tokens, whichever is smaller"}],"explanation":"The assistant looks back at your last 10 messages. That's enough for it to follow up on recent topics without dragging in the whole conversation."},{"id":"ai4","text":"You switch from the Procurement Assistant to the HR Assistant and then back to Procurement. What happens to your Procurement conversation?","options":[{"id":"a","text":"It's gone — switching assistants clears all conversations"},{"id":"b","text":"It's preserved in memory for the current session","isCorrect":true},{"id":"c","text":"It's saved to the database and can be resumed anytime"},{"id":"d","text":"Only the last 3 messages are kept; older ones are discarded"}],"explanation":"Conversations are maintained per-assistant in memory. Switching assistants doesn't clear anything — each assistant keeps its own conversation. However, conversations are not persisted, so closing the browser clears them."},{"id":"ai5","text":"You've just selected an assistant and the Clear Chat button is nowhere to be found in the chat header. Why isn't it shown?","options":[{"id":"a","text":"You don't have permission to clear chats"},{"id":"b","text":"The assistant is currently generating a response"},{"id":"c","text":"There are no messages in the current conversation — nothing to clear","isCorrect":true},{"id":"d","text":"Clear Chat is only available to Admin and Manager roles"}],"explanation":"The Clear Chat button is hidden when there are no messages — there's nothing to clear yet. Once you send at least one message, the button appears in the chat header."},{"id":"ai6","text":"What do the three animated dots in the chat area indicate?","options":[{"id":"a","text":"The assistant is offline and cannot respond"},{"id":"b","text":"Your message failed to send and is being retried"},{"id":"c","text":"The assistant is generating a response — a typing indicator","isCorrect":true},{"id":"d","text":"The system is loading the assistant's configuration"}],"explanation":"The typing indicator (three animated dots) appears while the assistant is processing your question and generating a response. The Send button is also disabled during this time."},{"id":"ai7","text":"You refresh the browser while chatting with an assistant. What happens to your conversation?","options":[{"id":"a","text":"It's fully restored from the server"},{"id":"b","text":"It's restored from your browser's saved history"},{"id":"c","text":"It's cleared — conversations only last for the current session","isCorrect":true},{"id":"d","text":"Only the last message is kept, through the page address"}],"explanation":"Conversations only last for your current session. Refreshing the page, closing the tab, or leaving clears them. That's on purpose — this feature is for quick questions, not long-term records."},{"id":"ai8","text":"Where do starter questions come from for each assistant?","options":[{"id":"a","text":"They're built into the app and can't be changed"},{"id":"b","text":"An admin sets them up in the AI Assistants admin panel","isCorrect":true},{"id":"c","text":"The AI makes them up based on your role and recent activity"},{"id":"d","text":"They're pulled from the Training module's quiz questions"}],"explanation":"Starter questions are part of each assistant's setup. Admins add them in Admin → AI Assistants, and they show up on the assistant's welcome screen."},{"id":"ai9","text":"You want to share a link to the Procurement Assistant with a coworker. Is this possible?","options":[{"id":"a","text":"No — the AI page doesn't support direct linking to specific assistants"},{"id":"b","text":"Yes — the assistant is part of the page address, so you can copy and share the link","isCorrect":true},{"id":"c","text":"Yes, but only if you export the conversation first"},{"id":"d","text":"No — they need to navigate to the AI page and select the assistant manually"}],"explanation":"The assistant you're on is part of the page address, so the link takes a coworker straight to that assistant. They won't see your conversation, just the welcome screen."},{"id":"ai10","text":"The Send button is disabled even though you've typed a message. What's the most likely reason?","options":[{"id":"a","text":"The assistant is currently generating a response to your previous message","isCorrect":true},{"id":"b","text":"Your message exceeds the maximum character limit"},{"id":"c","text":"The assistant has been deactivated by an admin"},{"id":"d","text":"You need to select an assistant first before sending"}],"explanation":"Send is greyed out in two cases: when the box is empty, or while the assistant is writing a reply. Since you've already typed something, a reply is most likely still on its way."},{"id":"ai11","text":"What information does each assistant card in the sidebar display?","options":[{"id":"a","text":"Name only — you have to click to see details"},{"id":"b","text":"Icon, name, description, and a highlight on the selected assistant","isCorrect":true},{"id":"c","text":"Name, last message preview, and timestamp of last conversation"},{"id":"d","text":"Name, category, number of conversations, and a star rating"}],"explanation":"Each sidebar card shows the assistant's icon, name, and description, plus a highlight on whichever one you're using."},{"id":"ai12","text":"An admin wants to add a new AI assistant for the Quality department. Where do they configure it?","options":[{"id":"a","text":"In the AI page itself — click 'New Assistant' in the sidebar"},{"id":"b","text":"In Admin → AI Assistants — create a new assistant with a name, description, icon, color, category, and starter questions","isCorrect":true},{"id":"c","text":"By editing a configuration file and restarting the server"},{"id":"d","text":"In Admin → System Settings under the AI section"}],"explanation":"AI assistants are managed in Admin → AI Assistants. Admins create, edit, and turn assistants on or off there, and the changes show up for users right away."}]}"""
